class Solution {
public:
    Node* copyRandomList(Node* head) {
        if (!head) return nullptr;
        unordered_map<Node*, Node*> mp;
        for (Node* cur = head; cur; cur = cur->next)
            mp[cur] = new Node(cur->val);
        for (Node* cur = head; cur; cur = cur->next) {
            mp[cur]->next = mp.count(cur->next) ? mp[cur->next] : nullptr;
            mp[cur]->random = mp.count(cur->random) ? mp[cur->random] : nullptr;
        }
        return mp[head];
    }
};
